#include<bits/stdc++.h>
using namespace std;
const int N=5e4+5;
int a[N],b[N];
int main(){
	int n;
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++) cin>>b[i];
	sort(a+1,a+n+1);
	sort(b+1,b+n+1);
	int l=1,r=1;
	int ans=0;
	while(l<=n&&r<=n){
		if(a[l]<b[r]) l++;
		else{
			ans++;
			l++;
			r++;
		}
	}
	cout<<ans;
	return 0;
}
